"async function scanFile(logPath) {
  if (!fs.existsSync(logPath)) return null;
  const fileStream = fs.createReadStream(logPath);
  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  let index = 0;
  for await (const line of rl) {
    index++;
    // Look for occurrences of "sanskrit_name" and "price" and are relatively long (meaning they contain multiple products)
    if (line.includes('sanskrit_name') && line.includes('slug') && line.includes('original_price') && line.length > 10000) {
      console.log(`FOUND potential product array in ${path.basename(path.dirname(path.dirname(logPath)))} line ${index}, length: ${line.length}`);
      try {
        const parsed = JSON.parse(line);
        // Let's write it to a dump file
        const dumpPath = path.join(__dirname, `recovered_step_${parsed.step_index}.json`);
        fs.writeFileSync(dumpPath, JSON.stringify(parsed, null, 2));
        console.log(`Wrote dump to ${dumpPath}`);
      } catch (e) {
        console.error('Error parsing line JSON:', e.message);
      }
    }
  }
}"
